#!/usr/bin/env php
<?php
declare(strict_types=1);
use App\Core\Database; use App\Core\Env; use App\Services\EmailService;
require dirname(__DIR__).'/app/core/Env.php';Env::load(dirname(__DIR__).'/.env');spl_autoload_register(function(string $class):void{$prefix='App\\';if(!str_starts_with($class,$prefix))return;$relative=substr($class,strlen($prefix));$parts=explode('\\',$relative);$parts[0]=strtolower($parts[0]);$file=dirname(__DIR__).'/app/'.implode('/',$parts).'.php';if(is_file($file))require $file;});require dirname(__DIR__).'/app/helpers/functions.php';
$pdo=Database::connection();$rows=$pdo->query("SELECT i.*,c.display_name,c.email,c.portal_token FROM invoices i JOIN customers c ON c.id=i.customer_id WHERE i.balance_due>0 AND i.due_date<CURDATE() AND c.email IS NOT NULL AND DATEDIFF(CURDATE(),i.due_date) IN (1,7,15,30)")->fetchAll();$sent=0;foreach($rows as $r){$days=(int)((new DateTime($r['due_date']))->diff(new DateTime())->days);$subject='Payment reminder: '.$r['invoice_number'];$body='<p>Hello '.e($r['display_name']).',</p><p>Invoice <strong>'.e($r['invoice_number']).'</strong> has an outstanding balance of <strong>'.money($r['balance_due']).'</strong> and is '.$days.' day(s) overdue.</p><p>Please review your customer portal or contact Rock Bluffs Exterior Services if arrangements are needed.</p>';try{(new EmailService())->sendMail($r['email'],$subject,$body);$pdo->prepare("INSERT INTO collection_actions(invoice_id,action_type,notes,status) VALUES(?,'email',?,'completed')")->execute([$r['id'],'Automated '.$days.'-day overdue reminder sent.']);$sent++;}catch(Throwable $e){fwrite(STDERR,$e->getMessage().PHP_EOL);}}echo $sent." collection reminder(s) sent.\n";
